import random

def simulate_browse(current, graph, damping=0.85):
    # Roll a die to see if we 'Jump' or 'Click'
    if random.random() < (1 - damping):
        return "[TELEPORT] to random page"

    # Click a link from current page
    links = graph.get(current, [])
    if not links:
        return f"[STUCK] at {current} (no links)"
    return f"[CLICK] to {random.choice(links)}"

web = {
    "p1": ["p2", "p3"],
    "p2": ["p3"],
    "p3": []
}

print(f"User at P1: {simulate_browse('p1', web)}")
